VALUES
  ('social-worker-moex-02811', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關過動兒的敘述中，下列何者最為恰當？', '["過動兒對他人漠不關心，往往視若無睹", "過動兒的成因基本上都是先天的", "過動兒需要環境的一致性和穩定性", "過動兒產生的主因是缺乏注意力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02812', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '當青少年開始探索自我認同課題時，往往也會啟動個體化（individuation）的過程。下列有關個體化的敘 述中，何者不恰當？', '["青少年期的個體化，係指青少年發展出獨特的自我或認同的過程", "青少年期的個體化，就是在生活功能、態度、情緒等等面向朝向自立而不再依附父母安排的過程", "青少年期個體化的過程中，與父母分離的元素，不包括衝突獨立（conflictual independence）", "青少年期的個體化，不僅存在著世代差異，也存在同世代青少年彼此間的個別差異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02813', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關自閉症者行為表現的特徵，下列敘述何者正確？', '["社會性障礙、溝通障礙、行為興趣的固執性和有限性", "社會性障礙、溝通障礙、情緒障礙", "溝通障礙、情緒障礙、行為興趣的固執性和有限性", "社會性障礙、溝通障礙、心智性障礙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02814', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何種理論認為：兒童期是道德發展關鍵期，若能在其生活環境中有適當長輩可供模仿和予以適當指 導，則上行下效，有助提升兒童的道德認知水準？', '["近側最佳化發展區理論", "皮亞傑（Piaget）的道德認知發展理論", "柯柏格（Kohlberg）的道德認知發展理論", "近朱者赤之品格教育理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02815', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '探討性別議題的學者認為，中年危機主要是女性的常態過程，對於男性而言則較少發生，其主要理由乃：', '["女性會有更年期，男性則無", "中年期親職負擔減輕後，因為婦女的角色比男人多樣和複雜，其角色重整的難度相對較高", "一般而言，中年期男人比婦女擁有較多權力和資源，較不易感受變遷壓力和危機", "兩性的生理和心理結構存在本質的差異，中年期的婦女調適相對不易"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02816', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關中年期特徵之描述中，下列何者錯誤？', '["相對於其他階段而言，中年期的人們較少受到生理變化的影響", "由於可塑性小，相對於其他階段而言，中年期是人們在個別經驗上彼此差異最小的時期", "由於個別差異趨大，按特定的年齡來界定中年期，已經越來越不恰當", "不同世代的中年人，會受其所處環境和歷史事件的影響，而呈現明顯差異"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02817', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依佛洛伊德（Sigmund Freud）的理論，年滿50歲以上的人，其人格特質會呈現下列何種特性？', '["會隨年紀增長而持續變遷調適", "女性的改變比男性改變的可能性大", "不同文化族群者會有不同差異，不能一概而論", "已經定型，不易改變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02818', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依柯柏格（Kohlberg）的道德發展理論，下列敘述何者最能描述5歲兒童的行為特性？', '["能按簡單的社會規範表現行為", "還停留在無律階段，行為沒有一定的規律性", "會基於避免被懲罰來表現行為", "主要依賞罰的條件來調整行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02819', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依皮亞傑（Piaget）認知發展理論，下列何者最能適切描述10歲左右兒童的認知發展情形？', '["已經有抽象邏輯分析推理的能力", "已經能使用語言及符號等來體驗世界", "已經能夠從事物的分類、比較以了解其間的關係", "已經發展出物體恆存的概念"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02820', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '許多兒童在歷經多次失敗後，認為再多的努力也無濟於事，就不再繼續嘗試。兒童的此種行為現象，被 稱為：', '["他發型無力感", "內化的挫折感", "習得的無助感", "自我剝奪感"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02821', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '老年人口中最為盛行的兩種認知障礙是：', '["妄想症和失智症", "焦慮症和失智症", "憂鬱症和焦慮症", "妄想症和憂鬱症"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02822', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '就接受安寧照顧的基本要件而言，下列敘述何者錯誤？', '["病人的餘年不可超過6個月", "病人的年齡必須超過65歲", "照顧地點以家庭為主", "提供臨終病人以疼痛和症狀控制的醫療照顧為主"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02823', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關強暴的敘述中，何者錯誤？', '["強暴不只限發生在陌生人之間，也可能發生在彼此認識的人之間", "約會強暴並不等同於熟識者強暴", "約會強暴是指婦女被正在與她交往的對象強力勸誘而發生性關係的行為", "由於約會強暴被揭發的比率偏低，所以被視為一種隱藏性的犯罪行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02824', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '老人虐待有很多種形式，不當與非法使用老人的財務或資源，也是其中一種，稱為：', '["消極虐待", "間接虐待", "物質虐待", "積極虐待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02825', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '校園霸凌事件，往往引發社會關注，它是個複雜的現象，它大可分為直接霸凌和間接霸凌。是否為直接 霸凌，係根據下列何種標準來界分？', '["有無侵害身體", "有無面對面互動", "有沒有產生傷害後果", "有沒有透過他人來進行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02826', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關種族主義的敘述中，下列何者最不適切？', '["多元文化主義和種族主義是對立的，前者係反壓迫、反歧視的，而後者則蘊含優勢族群對弱勢族群的 壓迫與歧視", "自族中心主義是一般人很自然地以自我族群為中心的思維方式，它與壓迫、歧視無關，也與種族主義 無關", "種族主義不容易被明顯辨識出來，但可推測它仍存在我們的生活世界中", "種族主義很可能在既支持又壓迫弱勢族群的社會制度中巧妙地存在"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02827', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關性傾向課題的敘述中，下列敘述何者錯誤？', '["人們的性傾向大多在青少年期即已萌發", "有些同性戀者對自己會有「主觀同性戀厭惡感（internalized homophobia）」", "同性戀（homosexual）包含同志（gay）、女同志（lesbian）、雙性戀（bisexual）及灰色性戀（questioning individuals）等", "和異性戀者相比，同性戀者通常有較嚴重的心理疾病"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02828', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '三歲的阿威相信太陽一生氣就會躲到烏雲後面。根據皮亞傑（Piaget）的發展觀點，這是何種心智特徵的 表現？', '["自我中心（egocentrism）", "萬物有靈論（animism）", "具體運思（concrete operation）", "抽象思考（abstraction）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02829', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據班度拉（Albert Bandura）的社會學習理論（social learning），下列相關陳述何者不合理？', '["班度拉鑑於操作制約原則過於簡化所有人類的學習歷程，探討自我效能的信念對學習與社會化的左右 能力", "班度拉認為人類的學習是個人與其特殊的社會環境持續交互作用的歷程", "社會學習論強調角色楷模對人格發展的重要性", "學習論的另一概念模仿是指個體在觀察學習時，對社會情境中某個人或團體行為學習的歷程，其歷程 呈機械式反應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02830', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者為皮亞傑（Piaget）「感覺動作期」（sensorimotor stage）的兒童認知特徵？', '["兒童還不能理解這個世界的物體運作規律，必須依賴成人去幫他思考", "兒童能以表徵符號運作的方式去推論物體運作的規律", "因為這時期兒童說話不順暢，無法探索他們是否理解詞彙", "兒童透過感覺與動作的交互過程以理解周遭物體運作的規律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02831', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列敘述何者錯誤？', '["民德（mores）是依民風裡所釐定之對或錯的處世和做事方法", "習俗是群體解決問題，處世與互動的方式", "任務團體（task groups）成立之主要目的在於完成原先釐定的任務", "自然團體（natural groups）是由於自然發生的事件所產生人與人之間互相排斥的團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02832', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列敘述何者錯誤？', '["同化（assimilation）是人類將新資訊納入既有知識體系或基模的認知之過程", "社會距離（social distance）是人際關係中人與人之間的高度親密關係", "利他主義（altruism）是助人的行為，出發點在於對他人的關懷，不是出自個人利益", "同性戀恐懼（homophobia）指對於同志的恐懼和仇恨，沒有任何理性或根據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02833', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據生態系統觀點，下列那一項敘述錯誤？', '["生態系統觀點強調雙重焦點：人與情境、系統與環境，以全人與環境交互作用並互相影響與被影響", "生態學是研究有機體與環境之間的學科，被應用分析人於情境中因應環境的挑戰與協調模式", "社會工作者在實務操作上只注重單向的影響", "在處遇關係上，個體和系統都會受到系統變遷作用的影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02834', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關X染色體易碎症（fragile X syndrome）的敘述，何者最正確？', '["脆弱的X染色體引發特納症候群（Turner’s syndrome）", "由母親只傳給女兒", "有缺陷的X染色體無法透過第21號染色體彌補其生物功能", "可能造成重度智能障礙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02835', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '爸爸當著六個月大的嬰兒阿丹把玩具卡車藏在毛巾底下時，阿丹不知如何去搜尋玩具車，皮亞傑（Piaget） 的學說指出原因，即六個月大的嬰兒缺乏以下那一個概念？', '["物體恆存性（object permanence）", "自我中心（egocentrism）", "認知失平衡（cognitive disequilibrium）", "具體運思（concrete operation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
